import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const P=JSON.parse('{"title":"活偶像","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/活偶像.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/活偶像.md"}'),d={name:"4.资源分区/1.血统与训练/6.一次性血统/活偶像.md"};function p(b,e,l,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"活偶像",tabindex:"-1"},[s("活偶像 "),r("a",{class:"header-anchor",href:"#活偶像","aria-label":'Permalink to "活偶像"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),o('<h1 id="活偶像-1" tabindex="-1">活偶像 <a class="header-anchor" href="#活偶像-1" aria-label="Permalink to &quot;活偶像&quot;">​</a></h1><p>活偶像<br> 价格：B+6666<br> 描述：像人类一样行走而不像人类一样思考。<br> 像活物一样行动而不为活着索求。<br> 拥有感情而不为同类起伏的话。<br> 是会被人们误以为具有“神性”的某物。<br> 而当相信成为力量，奇迹便会有限度的归咎于你。</p><p>【无用之人】：「“我即万物冗余的具现——”」<br> 如蛇的脚、猫的脚步声、女人的胡须、石头的根，鱼的呼吸、熊的脚腱和鸟的唾液那样万物万事可以拥有却没必要拥有之物的体现。<br> *你失去全属性上的附加成功（即传奇属性）带来的能力，这意味着你不会因为传奇力量而增加DP，也不会因为传奇敏捷而提升移动速度与AP，以此类推。<br> *只在剧情表现上，你的全属性视为1，若有人对你使用了解析类能力，只要其等级不超过A级，则也只能发现你的全属性为1。</p><p>【无能之人】：「“我为万事未决的准备——”」<br> 必须拥有杰出的天赋，而不去使用、对凡物有着强烈的怜悯。却不去行动、与此同时，他们作为人类的才能却必须要十分低下。<br> 比如说烹饪、打扫、锻炼、照顾小孩，以及其他“作为人类所应习得”的实用技能。如果掌握了，一定得是“没有什么用”的东西才行。<br> *你在全技能上检定上失去附加成功数，这只包括技能等级本身自带的附加成功数。<br> *只在剧情表现上，你的全技能视为1，若有人对你使用了解析类能力，只要其等级不超过A级，则也只能发现你的全技能为1。</p><p>【无限之人】：「“我乃万象空白的支点——”」<br> 「像是未雕刻的石碑/未开锋的剑胚/刚出生的婴儿那样，尚未成为任何成形之物，尚保留着接近无限可能性的状态 。其本身乃是“没能成就任何事，所以可以成就任何事的无限之人。”」<br> *每当你或者你的队友获得成长类能力提供的DP加值时（例如一个每影片结束时力量相关检定上获得1DP加值的能力【无限成长】，或一个获得传奇敏捷*2DP攻击检定上的速度加值【有限成长】等效果），你会再额外获得一次这部分dp加值，以此获得的额外加值最高等同你自身内在【最高支线等级*6】+6DP，且当一个检定同时计入多个因该能力获得的额外加值时，只有一个额外加值会生效（例如你因这一能力经过了一影片额外获得了传奇敏捷（3）*2＝6DP敏捷加值，又因为影片结束获得1DP攻击加值再额外成长了1DP攻击加值，你在以敏捷属性攻击时只会计算前置的6DP而非6+1=7DP。）</p><p>【神性（伪）】：「“或许我将成就世间万物万事万象。”」<br> *你总是在剧情中视为具有【神性】，这可能带来一些影响。<br> *你获得【不老】特性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const D=a(d,[["render",p]]);export{P as __pageData,D as default};
